import{_ as o,C as r,o as n,c as i,ai as a,E as d,w as l,a as s}from"./chunks/framework.BH_J6TYN.js";const f=JSON.parse('{"title":"Sección Menú","description":"Administra las categorías y platos de tu menú digital","frontmatter":{"title":"Sección Menú","description":"Administra las categorías y platos de tu menú digital"},"headers":[],"relativePath":"food/seccion-menu.md","filePath":"food/seccion-menu.md"}'),c={name:"food/seccion-menu.md"};function u(p,e,h,m,g,b){const t=r("Warning");return n(),i("div",null,[e[1]||(e[1]=a('<h2 id="¿que-es" tabindex="-1">¿Qué es? <a class="header-anchor" href="#¿que-es" aria-label="Permalink to &quot;¿Qué es?&quot;">​</a></h2><p>La sección Menú es donde administras todo el contenido de tu menú digital: categorías de comida, platos individuales con precio, fotos de categoría y orden de aparición. Es el corazón de SYNTIfood.</p><h2 id="¿donde-lo-encuentro" tabindex="-1">¿Dónde lo encuentro? <a class="header-anchor" href="#¿donde-lo-encuentro" aria-label="Permalink to &quot;¿Dónde lo encuentro?&quot;">​</a></h2><p><strong>Tu panel → Qué Vendes</strong> (segundo ícono en el menú lateral, 🛒)</p><p>En SYNTIfood, este tab muestra la gestión del menú en lugar de productos/servicios genéricos.</p><h2 id="¿que-hace" tabindex="-1">¿Qué hace? <a class="header-anchor" href="#¿que-hace" aria-label="Permalink to &quot;¿Qué hace?&quot;">​</a></h2><h3 id="gestion-de-categorias" tabindex="-1">Gestión de categorías <a class="header-anchor" href="#gestion-de-categorias" aria-label="Permalink to &quot;Gestión de categorías&quot;">​</a></h3><p>Las categorías organizan tu menú (ej: &quot;Arepas&quot;, &quot;Carnes&quot;, &quot;Bebidas&quot;, &quot;Postres&quot;). Cada categoría tiene:</p><table tabindex="0"><thead><tr><th>Campo</th><th>Obligatorio</th><th>Descripción</th></tr></thead><tbody><tr><td><strong>Nombre de categoría</strong></td><td>✅ Sí</td><td>Nombre visible en el menú (ej: &quot;Pescados&quot;)</td></tr><tr><td><strong>Foto de categoría</strong></td><td>No</td><td>1 imagen representativa (máx 2MB, auto WebP)</td></tr><tr><td><strong>Orden</strong></td><td>No</td><td>Posición en la que aparece en el menú</td></tr></tbody></table><h3 id="gestion-de-items-platos" tabindex="-1">Gestión de ítems (platos) <a class="header-anchor" href="#gestion-de-items-platos" aria-label="Permalink to &quot;Gestión de ítems (platos)&quot;">​</a></h3><p>Dentro de cada categoría, agregas los platos individuales:</p><table tabindex="0"><thead><tr><th>Campo</th><th>Obligatorio</th><th>Descripción</th></tr></thead><tbody><tr><td><strong>Nombre del plato</strong></td><td>✅ Sí</td><td>Nombre del ítem (ej: &quot;Arepa reina pepiada&quot;)</td></tr><tr><td><strong>Precio</strong></td><td>✅ Sí</td><td>Precio en REF</td></tr><tr><td><strong>Descripción</strong></td><td>No</td><td>Descripción corta (ingredientes, porciones)</td></tr><tr><td><strong>Disponible</strong></td><td>—</td><td>Toggle para marcar como disponible/agotado</td></tr></tbody></table><h3 id="en-la-landing-lo-que-ve-tu-cliente" tabindex="-1">En la landing (lo que ve tu cliente) <a class="header-anchor" href="#en-la-landing-lo-que-ve-tu-cliente" aria-label="Permalink to &quot;En la landing (lo que ve tu cliente)&quot;">​</a></h3><p>El menú se muestra en formato <strong>híbrido</strong>:</p><ul><li><strong>Categoría:</strong> Nombre + 1 foto grande representativa</li><li><strong>Debajo:</strong> Lista de platos con nombre, precio y botón [+] (si tiene Pedido Rápido)</li></ul><h2 id="¿que-no-hace" tabindex="-1">¿Qué NO hace? <a class="header-anchor" href="#¿que-no-hace" aria-label="Permalink to &quot;¿Qué NO hace?&quot;">​</a></h2><ul><li>No permite foto individual por plato — solo 1 foto por categoría</li><li>No tiene descripción larga por plato — solo nombre + precio</li><li>No tiene alérgenos ni información nutricional</li><li>No marca automáticamente como &quot;agotado&quot; — lo haces tú manualmente</li><li>No tiene horario por categoría (ej: &quot;desayunos solo hasta las 11&quot;)</li></ul><h2 id="disponibilidad-por-plan" tabindex="-1">Disponibilidad por plan <a class="header-anchor" href="#disponibilidad-por-plan" aria-label="Permalink to &quot;Disponibilidad por plan&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Característica</th><th>Básico</th><th>Semestral</th><th>Anual</th></tr></thead><tbody><tr><td>Ítems totales</td><td>50</td><td>100</td><td>150</td></tr><tr><td>Fotos de categoría</td><td>6</td><td>12</td><td>18</td></tr><tr><td>Categorías</td><td>❌ (menú plano)</td><td>✅</td><td>✅</td></tr><tr><td>Orden personalizable</td><td>✅</td><td>✅</td><td>✅</td></tr></tbody></table>',19)),d(t,null,{default:l(()=>[...e[0]||(e[0]=[s(" En el plan **Básico**, no hay categorías. Todos los platos aparecen en una lista plana sin agrupación. Para organizar tu menú por categorías necesitas el plan **Semestral** o **Anual**. ",-1)])]),_:1}),e[2]||(e[2]=a('<h2 id="ejemplo-practico" tabindex="-1">Ejemplo práctico <a class="header-anchor" href="#ejemplo-practico" aria-label="Permalink to &quot;Ejemplo práctico&quot;">​</a></h2><h3 id="caso-restaurante-sabor-criollo-en-valencia" tabindex="-1">Caso: Restaurante &quot;Sabor Criollo&quot; en Valencia <a class="header-anchor" href="#caso-restaurante-sabor-criollo-en-valencia" aria-label="Permalink to &quot;Caso: Restaurante &quot;Sabor Criollo&quot; en Valencia&quot;">​</a></h3><p>Carmen tiene un restaurante con plan Anual (150 ítems, 18 fotos):</p><ol><li>Crea categoría &quot;Desayunos&quot; → sube foto de empanadas y café</li><li>Agrega: Empanada de queso REF 1.50, Empanada de carne REF 2, Café con leche REF 1</li><li>Crea categoría &quot;Almuerzos&quot; → sube foto de pabellón criollo</li><li>Agrega: Pabellón REF 6, Asado negro REF 7, Pollo en brasa REF 5.50</li><li>Crea categoría &quot;Bebidas&quot; → sube foto de jugos</li><li>Agrega: Jugo natural REF 2, Agua REF 1, Refresco REF 1.50</li></ol><p>El menú aparece organizado: primero desayunos con su foto, debajo la lista de platos. Luego almuerzos, etc. Simple, rápido de cargar y fácil de leer.</p><h2 id="ver-tambien" tabindex="-1">Ver también <a class="header-anchor" href="#ver-tambien" aria-label="Permalink to &quot;Ver también&quot;">​</a></h2><ul><li><a href="/food/categorias-e-items.html">Categorías e ítems</a> — Estructura detallada</li><li><a href="/food/extras-opciones.html">Extras y opciones</a> — Personalización de platos (Semestral+)</li><li><a href="/food/pedido-rapido.html">Pedido Rápido</a> — El acumulador de platos → WhatsApp</li></ul>',7))])}const _=o(c,[["render",u]]);export{f as __pageData,_ as default};
